+/**
+ * V3 CLI Session Command
+ * Session management for Claude Flow
+ */
+
+import type { Command, CommandContext, CommandResult } from '../types.js';
+import { output } from '../output.js';
+import { confirm, input, select } from '../prompt.js';
+import { callMCPTool, MCPClientError } from '../mcp-client.js';
+import * as fs from 'fs';
+import * as path from 'path';
+
+// Format date for display
+function formatDate(dateStr: string): string {
+  const date = new Date(dateStr);
+  const now = new Date();
+  const diff = now.getTime() - date.getTime();
+
+  // Less than 24 hours - show relative time
+  if (diff < 24 * 60 * 60 * 1000) {
+    const hours = Math.floor(diff / (60 * 60 * 1000));
+    const minutes = Math.floor((diff % (60 * 60 * 1000)) / (60 * 1000));
+
+    if (hours > 0) {
+      return `${hours}h ${minutes}m ago`;
+    }
+    return `${minutes}m ago`;
+  }
+
+  // Otherwise show date
+  return date.toLocaleDateString() + ' ' + date.toLocaleTimeString();
+}
+
+// Format session status
+function formatStatus(status: string): string {
+  switch (status) {
+    case 'active':
+      return output.success(status);
+    case 'saved':
+      return output.info(status);
+    case 'archived':
+      return output.dim(status);
+    default:
+      return status;
+  }
+}
+
+// List subcommand
+const listCommand: Command = {
+  name: 'list',
+  aliases: ['ls'],
+  description: 'List all sessions',
+  options: [
+    {
+      name: 'active',
+      short: 'a',
+      description: 'Show only active sessions',
+      type: 'boolean',
+      default: false
+    },
+    {
+      name: 'all',
+      description: 'Include archived sessions',
+      type: 'boolean',
+      default: false
+    },
+    {
+      name: 'limit',
+      short: 'l',
+      description: 'Maximum sessions to show',
+      type: 'number',
+      default: 20
+    }
+  ],
+  action: async (ctx: CommandContext): Promise<CommandResult> => {
+    const activeOnly = ctx.flags.active as boolean;
+    const includeArchived = ctx.flags.all as boolean;
+    const limit = ctx.flags.limit as number;
+
+    try {
+      const result = await callMCPTool<{
+        sessions: Array<{
+          id: string;
+          name?: string;
+          description?: string;
+          status: 'active' | 'saved' | 'archived';
+          createdAt: string;
+          updatedAt: string;
+          agentCount: number;
