+// Simple YAML parser for config (basic implementation)
+function parseSimpleYaml(content: string): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  const lines = content.split('\n');
+  const stack: Array<{ indent: number; obj: Record<string, unknown>; key?: string }> = [
+    { indent: -1, obj: result }
+  ];
+
+  for (const line of lines) {
+    // Skip comments and empty lines
+    if (line.trim().startsWith('#') || line.trim() === '') continue;
+
+    const match = line.match(/^(\s*)(\w+):\s*(.*)$/);
+    if (!match) continue;
+
+    const indent = match[1].length;
+    const key = match[2];
+    let value: unknown = match[3].trim();
+
+    // Parse value
+    if (value === '' || value === undefined) {
+      value = {};
+    } else if (value === 'true') {
+      value = true;
+    } else if (value === 'false') {
+      value = false;
+    } else if (value === 'null') {
+      value = null;
+    } else if (!isNaN(Number(value)) && value !== '') {
+      value = Number(value);
+    } else if (value.startsWith('"') && value.endsWith('"')) {
+      value = value.slice(1, -1);
+    }
+
+    // Find parent based on indentation
+    while (stack.length > 1 && stack[stack.length - 1].indent >= indent) {
+      stack.pop();
+    }
+
+    const parent = stack[stack.length - 1].obj;
+
+    if (typeof value === 'object' && value !== null) {
+      parent[key] = value;
+      stack.push({ indent, obj: value as Record<string, unknown>, key });
+    } else {
+      parent[key] = value;
+    }
+  }
+
+  return result;
+}
